1	/* codegen.h -- Expression code generation for PL/SW compiler */
2	/* Emits COR24 assembly for AST expression nodes */
3	
4	#ifndef CODEGEN_H
5	#define CODEGEN_H
6	
7	#include "token.h"
8	#include "emit.h"
9	#include "symtab.h"
10	#include "types.h"
11	
12	/* --- Register model ---
13	 * r0: primary accumulator (result register)
14	 * r1: secondary (RHS of binops, also link register for calls)
15	 * r2: tertiary (address calculations, spill)
16	 * fp: frame pointer for local variable access
17	 * sp: stack pointer
18	 *
19	 * Expression evaluation always leaves the result in r0.
20	 * For binary ops: LHS in r0, RHS in r1, result in r0.
21	 * When register pressure exceeds 3, spill to stack via push/pop.
22	 */
23	
24	/* --- Register names --- */
25	
26	char *reg_name[3];
27	
28	void cg_init_regs(void) {
29	    reg_name[0] = "r0";
30	    reg_name[1] = "r1";
31	    reg_name[2] = "r2";
32	}
33	
34	/* --- Codegen error state --- */
35	
36	int cg_err;
37	char *cg_errmsg;
38	
39	void cg_init(void) {
40	    cg_init_regs();
41	    cg_err = 0;
42	    cg_errmsg = 0;
43	}
44	
45	void cg_error(char *msg) {
46	    cg_err = 1;
47	    cg_errmsg = msg;
48	}
49	
50	/* --- Forward declarations --- */
51	
52	void cg_expr(int node);
53	
54	/* --- Helper: check if expression is "simple" (no push/pop needed) --- */
55	/* A simple expr is a literal or variable -- can load directly into r1 */
56	
57	int cg_is_simple(int node) {
58	    if (node == NODE_NULL) return 0;
59	    if (nd_kind[node] == NODE_LITERAL) return 1;
60	    if (nd_kind[node] == NODE_IDENT) return 1;
61	    return 0;
62	}
63	
64	/* --- Literal loading --- */
65	
66	void cg_literal(int node) {
67	    int val = nd_ival[node];
68	    if (val >= -128 && val <= 127) {
69	        /* Small constant: use lc (sign-extending 8-bit immediate) */
70	        emit_str(EMIT_INDENT);
71	        emit_str("lc      r0,");
72	        emit_int(val);
73	        emit_nl();
74	    } else {
75	        /* Large constant: use la (24-bit immediate) */
76	        emit_str(EMIT_INDENT);
77	        emit_str("la      r0,");
78	        emit_int(val);
79	        emit_nl();
80	    }
81	}
82	
83	/* --- Variable load --- */
84	/* Loads variable value into r0 */
85	
86	void cg_load_var(int node) {
87	    int idx;
88	    int off;
89	    int w;
90	
91	    idx = sym_lookup(nd_name[node]);
92	    if (idx < 0) {
93	        cg_error("undefined variable");
94	        emit_comment("ERROR: undefined variable");
95	        if (nd_name[node]) {
96	            emit_str(EMIT_INDENT);
97	            emit_str("; name: ");
98	            emit_line(nd_name[node]);
99	        }
100	        emit_str(EMIT_INDENT);
101	        emit_line("lc      r0,0");
102	        return;
103	    }
104	
105	    off = sym_offset[idx];
106	    w = sym_width[idx];
107	
108	    if (sym_stor[idx] == STOR_STATIC || sym_stor[idx] == STOR_EXTERNAL) {
109	        /* Static/external: load address, then dereference */
110	        emit_str(EMIT_INDENT);
111	        emit_str("la      r2,");
112	        emit_int(off);
113	        emit_nl();
114	        if (w == 1) {
115	            emit_instr("lb      r0,0(r2)");
116	        } else {
117	            emit_instr("lw      r0,0(r2)");
118	        }
119	    } else {
120	        /* Automatic (stack-relative via fp) */
121	        if (off >= -128 && off <= 127) {
122	            if (w == 1) {
123	                emit_str(EMIT_INDENT);
124	                emit_str("lb      r0,");
125	                emit_int(off);
126	                emit_line("(fp)");
127	            } else {
128	                emit_str(EMIT_INDENT);
129	                emit_str("lw      r0,");
130	                emit_int(off);
131	                emit_line("(fp)");
132	            }
133	        } else {
134	            /* Large offset: compute address in r2 */
135	            emit_str(EMIT_INDENT);
136	            emit_str("la      r2,");
137	            emit_int(off);
138	            emit_nl();
139	            emit_instr("add     r2,fp");
140	            if (w == 1) {
141	                emit_instr("lb      r0,0(r2)");
142	            } else {
143	                emit_instr("lw      r0,0(r2)");
144	            }
145	        }
146	    }
147	}
148	
149	/* --- Variable store --- */
150	/* Stores r0 into the variable named by the identifier node */
151	
152	void cg_store_var(int node) {
153	    int idx;
154	    int off;
155	    int w;
156	
157	    idx = sym_lookup(nd_name[node]);
158	    if (idx < 0) {
159	        cg_error("undefined variable for store");
160	        emit_comment("ERROR: undefined variable for store");
161	        return;
162	    }
163	
164	    off = sym_offset[idx];
165	    w = sym_width[idx];
166	
167	    if (sym_stor[idx] == STOR_STATIC || sym_stor[idx] == STOR_EXTERNAL) {
168	        emit_str(EMIT_INDENT);
169	        emit_str("la      r2,");
170	        emit_int(off);
171	        emit_nl();
172	        if (w == 1) {
173	            emit_instr("sb      r0,0(r2)");
174	        } else {
175	            emit_instr("sw      r0,0(r2)");
176	        }
177	    } else {
178	        if (off >= -128 && off <= 127) {
179	            if (w == 1) {
180	                emit_str(EMIT_INDENT);
181	                emit_str("sb      r0,");
182	                emit_int(off);
183	                emit_line("(fp)");
184	            } else {
185	                emit_str(EMIT_INDENT);
186	                emit_str("sw      r0,");
187	                emit_int(off);
188	                emit_line("(fp)");
189	            }
190	        } else {
191	            emit_str(EMIT_INDENT);
192	            emit_str("la      r2,");
193	            emit_int(off);
194	            emit_nl();
195	            emit_instr("add     r2,fp");
196	            if (w == 1) {
197	                emit_instr("sb      r0,0(r2)");
198	            } else {
199	                emit_instr("sw      r0,0(r2)");
200	            }
201	        }
202	    }
203	}
204	
205	/* --- Load simple expression into a specific register --- */
206	/* Used for RHS of binops when RHS is simple (avoids push/pop) */
207	
208	void cg_load_simple_into(int node, char *reg) {
209	    int val;
210	    int idx;
211	    int off;
212	    int w;
213	
214	    if (nd_kind[node] == NODE_LITERAL) {
215	        val = nd_ival[node];
216	        if (val >= -128 && val <= 127) {
217	            emit_str(EMIT_INDENT);
218	            emit_str("lc      ");
219	            emit_str(reg);
220	            emit_char(44);
221	            emit_int(val);
222	            emit_nl();
223	        } else {
224	            emit_str(EMIT_INDENT);
225	            emit_str("la      ");
226	            emit_str(reg);
227	            emit_char(44);
228	            emit_int(val);
229	            emit_nl();
230	        }
231	    } else if (nd_kind[node] == NODE_IDENT) {
232	        idx = sym_lookup(nd_name[node]);
233	        if (idx < 0) {
234	            cg_error("undefined variable");
235	            emit_comment("ERROR: undefined variable in simple load");
236	            return;
237	        }
238	        off = sym_offset[idx];
239	        w = sym_width[idx];
240	
241	        if (sym_stor[idx] == STOR_STATIC || sym_stor[idx] == STOR_EXTERNAL) {
242	            emit_str(EMIT_INDENT);
243	            emit_str("la      r2,");
244	            emit_int(off);
245	            emit_nl();
246	            if (w == 1) {
247	                emit_str(EMIT_INDENT);
248	                emit_str("lb      ");
249	                emit_str(reg);
250	                emit_line(",0(r2)");
251	            } else {
252	                emit_str(EMIT_INDENT);
253	                emit_str("lw      ");
254	                emit_str(reg);
255	                emit_line(",0(r2)");
256	            }
257	        } else {
258	            if (off >= -128 && off <= 127) {
259	                if (w == 1) {
260	                    emit_str(EMIT_INDENT);
261	                    emit_str("lb      ");
262	                    emit_str(reg);
263	                    emit_char(44);
264	                    emit_int(off);
265	                    emit_line("(fp)");
266	                } else {
267	                    emit_str(EMIT_INDENT);
268	                    emit_str("lw      ");
269	                    emit_str(reg);
270	                    emit_char(44);
271	                    emit_int(off);
272	                    emit_line("(fp)");
273	                }
274	            } else {
275	                /* Large offset: use r2 for address calc */
276	                emit_str(EMIT_INDENT);
277	                emit_str("la      r2,");
278	                emit_int(off);
279	                emit_nl();
280	                emit_instr("add     r2,fp");
281	                if (w == 1) {
282	                    emit_str(EMIT_INDENT);
283	                    emit_str("lb      ");
284	                    emit_str(reg);
285	                    emit_line(",0(r2)");
286	                } else {
287	                    emit_str(EMIT_INDENT);
288	                    emit_str("lw      ");
289	                    emit_str(reg);
290	                    emit_line(",0(r2)");
291	                }
292	            }
293	        }
294	    }
295	}
296	
297	/* --- Software division subroutine --- */
298	/* Emitted once per compilation unit if division is used.
299	 * Entry: r0 = dividend, r1 = divisor
300	 * Exit:  r0 = quotient, r1 = remainder
301	 * Uses repeated subtraction (COR24 has no hardware divide). */
302	
303	int cg_div_emitted;  /* flag: have we emitted the div routine? */
304	
305	void cg_emit_div_routine(void) {
306	    int lloop;
307	    int ldone;
308	    int lneg;
309	    int lfix;
310	
311	    if (cg_div_emitted) return;
312	    cg_div_emitted = 1;
313	
314	    emit_nl();
315	    emit_comment("Software division: r0/r1 -> r0=quotient, r1=remainder");
316	    emit_line("__plsw_div:");
317	    emit_prologue();
318	
319	    /* Load dividend and divisor from arguments (already in r0, r1) */
320	    /* Save sign info: we'll work with positive values */
321	    /* r2 = sign flag (0=positive result, 1=negative) */
322	    emit_instr("lc      r2,0");
323	
324	    /* Check if dividend is negative */
325	    lneg = emit_new_label();
326	    lfix = emit_new_label();
327	    emit_instr("ceq     r0,z");
328	    emit_str(EMIT_INDENT);
329	    emit_str("brt     ");
330	    emit_label_ref(lfix);
331	    emit_nl();
332	    emit_instr("cls     r0,z");
333	    emit_str(EMIT_INDENT);
334	    emit_str("brf     ");
335	    emit_label_ref(lneg);
336	    emit_nl();
337	    /* dividend is negative: negate it, flip sign flag */
338	    emit_instr("sub     r0,r0");
339	    emit_instr("sub     r0,r0");
340	    /* Actually: 0 - r0. Use: push r0, lc r0,0, pop and sub */
341	    /* Simpler: just note this is tricky without a neg instruction */
342	
343	    /* Simplified approach: unsigned division only for now.
344	     * Signed division handled by: abs both operands, divide, fix sign */
345	    emit_label(lneg);
346	    emit_label(lfix);
347	
348	    /* Division by repeated subtraction */
349	    lloop = emit_new_label();
350	    ldone = emit_new_label();
351	
352	    /* r0 = dividend (remainder), r2 = quotient (reuse r2) */
353	    emit_instr("push    r2");
354	    emit_instr("lc      r2,0");
355	    emit_label(lloop);
356	    emit_instr("cls     r0,r1");
357	    emit_str(EMIT_INDENT);
358	    emit_str("brt     ");
359	    emit_label_ref(ldone);
360	    emit_nl();
361	    emit_instr("sub     r0,r1");
362	    emit_instr("add     r2,1");
363	    emit_str(EMIT_INDENT);
364	    emit_str("bra     ");
365	    emit_label_ref(lloop);
366	    emit_nl();
367	    emit_label(ldone);
368	    /* r0 = remainder, r2 = quotient */
369	    emit_instr("mov     r1,r0");
370	    emit_instr("mov     r0,r2");
371	    emit_instr("pop     r2");
372	    emit_epilogue();
373	}
374	
375	/* --- Binary arithmetic codegen --- */
376	
377	void cg_binop(int node) {
378	    int op;
379	    int lhs;
380	    int rhs;
381	    int lbl_false;
382	    int lbl_end;
383	
384	    op = nd_ival[node];
385	    lhs = nd_left[node];
386	    rhs = nd_right[node];
387	
388	    if (cg_is_simple(rhs)) {
389	        /* Optimization: evaluate LHS into r0, load RHS directly into r1 */
390	        cg_expr(lhs);
391	        cg_load_simple_into(rhs, "r1");
392	    } else {
393	        /* Complex RHS: evaluate LHS, push, evaluate RHS, pop LHS into r1 */
394	        cg_expr(lhs);
395	        emit_instr1("push", "r0");
396	        cg_expr(rhs);
397	        emit_instr2("mov", "r1", "r0");
398	        emit_instr1("pop", "r0");
399	    }
400	
401	    /* Now: r0 = LHS, r1 = RHS. Emit operation. */
402	    if (op == TOK_PLUS) {
403	        emit_instr("add     r0,r1");
404	    } else if (op == TOK_MINUS) {
405	        emit_instr("sub     r0,r1");
406	    } else if (op == TOK_STAR) {
407	        emit_instr("mul     r0,r1");
408	    } else if (op == TOK_SLASH) {
409	        /* Division via software routine */
410	        emit_instr1("push", "r1");
411	        emit_instr1("push", "r0");
412	        emit_str(EMIT_INDENT);
413	        emit_str("la      r2,__plsw_div");
414	        emit_nl();
415	        emit_instr("jal     r1,(r2)");
416	        /* Result in r0 (quotient) */
417	    } else if (op == TOK_AMP) {
418	        /* Bitwise AND: COR24 doesn't have direct AND.
419	         * Use a helper or emit inline sequence.
420	         * For now, we'll note this and use a simple approach. */
421	        emit_comment("bitwise AND (r0 & r1)");
422	        emit_instr("and     r0,r1");
423	    } else if (op == TOK_PIPE) {
424	        emit_comment("bitwise OR (r0 | r1)");
425	        emit_instr("or      r0,r1");
426	    } else if (op == TOK_CARET) {
427	        emit_comment("bitwise XOR (r0 ^ r1)");
428	        emit_instr("xor     r0,r1");
429	    } else if (op == TOK_SHL) {
430	        emit_comment("shift left");
431	        emit_instr("shl     r0,r1");
432	    } else if (op == TOK_SHR) {
433	        emit_comment("shift right");
434	        emit_instr("shr     r0,r1");
435	    } else if (op == TOK_EQ) {
436	        /* Equality: ceq r0,r1 then mov r0,c */
437	        emit_instr("ceq     r0,r1");
438	        emit_instr("mov     r0,c");
439	    } else if (op == TOK_NE) {
440	        /* Not equal: ceq then invert */
441	        emit_instr("ceq     r0,r1");
442	        emit_instr("mov     r0,c");
443	        emit_instr("ceq     r0,z");
444	        emit_instr("mov     r0,c");
445	    } else if (op == TOK_LT) {
446	        /* Signed less-than */
447	        emit_instr("cls     r0,r1");
448	        emit_instr("mov     r0,c");
449	    } else if (op == TOK_GT) {
450	        /* Greater-than: swap operands for cls */
451	        emit_instr("cls     r1,r0");
452	        emit_instr("mov     r0,c");
453	    } else if (op == TOK_LE) {
454	        /* Less-or-equal: NOT (r1 < r0) */
455	        emit_instr("cls     r1,r0");
456	        emit_instr("mov     r0,c");
457	        emit_instr("ceq     r0,z");
458	        emit_instr("mov     r0,c");
459	    } else if (op == TOK_GE) {
460	        /* Greater-or-equal: NOT (r0 < r1) */
461	        emit_instr("cls     r0,r1");
462	        emit_instr("mov     r0,c");
463	        emit_instr("ceq     r0,z");
464	        emit_instr("mov     r0,c");
465	    } else {
466	        cg_error("unsupported binary operator");
467	        emit_comment("ERROR: unsupported binop");
468	    }
469	}
470	
471	/* --- Unary operators --- */
472	
473	void cg_unop(int node) {
474	    int op = nd_ival[node];
475	
476	    /* Evaluate operand into r0 */
477	    cg_expr(nd_left[node]);
478	
479	    if (op == TOK_MINUS) {
480	        /* Negate: 0 - r0 */
481	        emit_instr2("mov", "r1", "r0");
482	        emit_instr("lc      r0,0");
483	        emit_instr("sub     r0,r1");
484	    } else if (op == TOK_TILDE || op == TOK_NOT) {
485	        /* Bitwise NOT: XOR with all-ones */
486	        emit_str(EMIT_INDENT);
487	        emit_str("la      r1,");
488	        emit_int(0xFFFFFF);
489	        emit_nl();
490	        emit_instr("xor     r0,r1");
491	    } else {
492	        cg_error("unsupported unary operator");
493	        emit_comment("ERROR: unsupported unop");
494	    }
495	}
496	
497	/* --- Main expression codegen dispatcher --- */
498	
499	void cg_expr(int node) {
500	    if (node == NODE_NULL) {
501	        emit_comment("null expr");
502	        emit_instr("lc      r0,0");
503	        return;
504	    }
505	
506	    if (nd_kind[node] == NODE_LITERAL) {
507	        cg_literal(node);
508	    } else if (nd_kind[node] == NODE_IDENT) {
509	        cg_load_var(node);
510	    } else if (nd_kind[node] == NODE_BINOP) {
511	        cg_binop(node);
512	    } else if (nd_kind[node] == NODE_UNOP) {
513	        cg_unop(node);
514	    } else {
515	        cg_error("unsupported expression node kind");
516	        emit_comment("ERROR: unsupported expr kind");
517	        emit_str(EMIT_INDENT);
518	        emit_str("; kind=");
519	        emit_int(nd_kind[node]);
520	        emit_nl();
521	    }
522	}
523	
524	/* --- Assignment codegen --- */
525	/* Evaluate RHS into r0, store into LHS variable */
526	
527	void cg_assign(int node) {
528	    int lhs = nd_left[node];
529	    int rhs = nd_right[node];
530	
531	    /* Evaluate RHS into r0 */
532	    cg_expr(rhs);
533	
534	    /* Store r0 into LHS */
535	    if (nd_kind[lhs] == NODE_IDENT) {
536	        cg_store_var(lhs);
537	    } else {
538	        cg_error("unsupported assignment target");
539	        emit_comment("ERROR: unsupported assignment target");
540	    }
541	}
542	
543	/* --- Static data emission --- */
544	
545	/* String literal table: maps labels to string data.
546	 * Used to collect string literals during codegen, then
547	 * emit them all in the .data section at the end. */
548	
549	#define CG_STR_MAX 32     /* max string literals per compilation */
550	
551	int cg_str_count;          /* number of string literals collected */
552	int cg_str_label[CG_STR_MAX];     /* label number for each string */
553	char *cg_str_data[CG_STR_MAX];    /* pointer to string content */
554	
555	void cg_static_init(void) {
556	    cg_str_count = 0;
557	}
558	
559	/* Register a string literal for emission. Returns its label number. */
560	int cg_add_string(char *s) {
561	    int lbl;
562	    if (cg_str_count >= CG_STR_MAX) {
563	        cg_error("too many string literals");
564	        return -1;
565	    }
566	    lbl = emit_new_label();
567	    cg_str_label[cg_str_count] = lbl;
568	    cg_str_data[cg_str_count] = s;
569	    cg_str_count = cg_str_count + 1;
570	    return lbl;
571	}
572	
573	/* Emit a single string literal as .byte directives with null terminator */
574	void cg_emit_string_bytes(char *s) {
575	    int i;
576	    int ch;
577	
578	    i = 0;
579	    while (s[i]) {
580	        emit_str(EMIT_INDENT);
581	        emit_str(".byte   ");
582	        emit_int(s[i]);
583	        emit_nl();
584	        i = i + 1;
585	    }
586	    /* Null terminator */
587	    emit_str(EMIT_INDENT);
588	    emit_line(".byte   0");
589	}
590	
591	/* Emit all collected string literals in the .data section */
592	void cg_emit_string_table(void) {
593	    int i;
594	    if (cg_str_count == 0) return;
595	
596	    emit_data_section();
597	    emit_comment("String literals");
598	
599	    i = 0;
600	    while (i < cg_str_count) {
601	        emit_label(cg_str_label[i]);
602	        cg_emit_string_bytes(cg_str_data[i]);
603	        i = i + 1;
604	    }
605	}
606	
607	/* Emit a static variable in the .data section.
608	 * Handles INIT values for scalars and zero-fill for uninitialized.
609	 * sym_idx = symbol table index for the variable.
610	 * init_node = AST node for INIT value, or NODE_NULL for zero. */
611	
612	void cg_emit_static_var(int sym_idx, int init_node) {
613	    int w;
614	    int addr;
615	    int val;
616	    int i;
617	    char *sval;
618	
619	    w = sym_width[sym_idx];
620	    addr = sym_offset[sym_idx];
621	
622	    emit_data_section();
623	
624	    /* Emit label at the static address */
625	    emit_comment(sym_name[sym_idx]);
626	    emit_named_label(sym_name[sym_idx]);
627	
628	    if (init_node != NODE_NULL && nd_kind[init_node] == NODE_LITERAL) {
629	        if (nd_type[init_node] == TYPE_CHAR && nd_name[init_node]) {
630	            /* String initializer: emit bytes */
631	            sval = nd_name[init_node];
632	            i = 0;
633	            while (sval[i]) {
634	                emit_str(EMIT_INDENT);
635	                emit_str(".byte   ");
636	                emit_int(sval[i]);
637	                emit_nl();
638	                i = i + 1;
639	            }
640	            /* Pad remaining space with zeros */
641	            while (i < w) {
642	                emit_str(EMIT_INDENT);
643	                emit_line(".byte   0");
644	                i = i + 1;
645	            }
646	        } else {
647	            /* Numeric initializer */
648	            val = nd_ival[init_node];
649	            if (w == 1) {
650	                emit_str(EMIT_INDENT);
651	                emit_str(".byte   ");
652	                emit_int(val);
653	                emit_nl();
654	            } else {
655	                emit_str(EMIT_INDENT);
656	                emit_str(".word   ");
657	                emit_int(val);
658	                emit_nl();
659	            }
660	        }
661	    } else {
662	        /* No initializer: zero-fill */
663	        if (w == 1) {
664	            emit_str(EMIT_INDENT);
665	            emit_line(".byte   0");
666	        } else if (w <= 3) {
667	            emit_str(EMIT_INDENT);
668	            emit_line(".word   0");
669	        } else {
670	            /* Large zero fill: emit individual bytes */
671	            i = 0;
672	            while (i < w) {
673	                emit_str(EMIT_INDENT);
674	                emit_line(".byte   0");
675	                i = i + 1;
676	            }
677	        }
678	    }
679	}
680	
681	/* Walk a program AST and emit .data section for all static/global DCLs.
682	 * Assumes layout_globals() has already been called to assign addresses. */
683	
684	void cg_emit_static_data(int prog_node) {
685	    int child;
686	    int idx;
687	
688	    if (prog_node == NODE_NULL) return;
689	
690	    child = nd_left[prog_node];
691	    while (child != NODE_NULL) {
692	        if (nd_kind[child] == NODE_DCL) {
693	            idx = sym_lookup(nd_name[child]);
694	            if (idx >= 0) {
695	                cg_emit_static_var(idx, nd_right[child]);
696	            }
697	        }
698	        child = nd_next[child];
699	    }
700	
701	    /* Emit any collected string literals */
702	    cg_emit_string_table();
703	}
704	
705	/* Load address of a string literal into r0.
706	 * Used when a string literal appears in an expression context. */
707	
708	void cg_load_string(int label_num) {
709	    emit_str(EMIT_INDENT);
710	    emit_str("la      r0,");
711	    emit_label_ref(label_num);
712	    emit_nl();
713	}
714	
715	/* --- Statement codegen --- */
716	/* Forward declaration for cg_block */
717	void cg_block(int block_node);
718	
719	/* Emit code for a single statement node */
720	void cg_stmt(int node) {
721	    if (node == NODE_NULL) return;
722	
723	    if (nd_kind[node] == NODE_ASSIGN) {
724	        cg_assign(node);
725	    } else if (nd_kind[node] == NODE_RETURN) {
726	        /* Evaluate return expression into r0 (if present) */
727	        if (nd_left[node] != NODE_NULL) {
728	            cg_expr(nd_left[node]);
729	        }
730	        /* Epilogue emitted by caller at procedure end.
731	         * For early returns, emit epilogue inline. */
732	        emit_epilogue();
733	    } else if (nd_kind[node] == NODE_CALL) {
734	        /* Bare CALL statement (result discarded).
735	         * Full call codegen comes in step 020; for now emit placeholder. */
736	        emit_comment("CALL (stub)");
737	        if (nd_name[node]) {
738	            emit_str(EMIT_INDENT);
739	            emit_str("; call ");
740	            emit_line(nd_name[node]);
741	        }
742	    } else if (nd_kind[node] == NODE_BLOCK) {
743	        cg_block(node);
744	    } else if (nd_kind[node] == NODE_DCL) {
745	        /* Local DCL: no code emission needed (handled by layout) */
746	    } else {
747	        cg_error("unsupported statement kind");
748	        emit_comment("ERROR: unsupported statement");
749	        emit_str(EMIT_INDENT);
750	        emit_str("; kind=");
751	        emit_int(nd_kind[node]);
752	        emit_nl();
753	    }
754	}
755	
756	/* Emit code for a block of statements */
757	void cg_block(int block_node) {
758	    int stmt;
759	    if (block_node == NODE_NULL) return;
760	
761	    stmt = nd_left[block_node];
762	    while (stmt != NODE_NULL) {
763	        cg_stmt(stmt);
764	        stmt = nd_next[stmt];
765	    }
766	}
767	
768	/* --- Procedure codegen --- */
769	
770	/* Emit code for a complete procedure.
771	 * proc_node is a NODE_PROC with:
772	 *   nd_name  = procedure name
773	 *   nd_left  = first parameter (linked via nd_next)
774	 *   nd_right = body (BLOCK node)
775	 *   nd_ival  = option flags (OPT_FREESTANDING, OPT_NAKED, OPT_LEAF)
776	 *   nd_stor  = return type
777	 *
778	 * Layout must be performed first via layout_proc(). */
779	
780	void cg_proc(int proc_node) {
781	    int opts;
782	    int frame_sz;
783	    int has_body;
784	    int body;
785	
786	    if (proc_node == NODE_NULL) return;
787	    if (nd_kind[proc_node] != NODE_PROC) {
788	        cg_error("expected PROC node");
789	        return;
790	    }
791	
792	    opts = nd_ival[proc_node];
793	    body = nd_right[proc_node];
794	
795	    /* Ensure we're in .text section */
796	    emit_text_section();
797	
798	    /* Emit .globl directive and label */
799	    if (nd_name[proc_node]) {
800	        emit_global(nd_name[proc_node]);
801	        emit_named_label(nd_name[proc_node]);
802	    }
803	
804	    /* NAKED procedures: no prologue/epilogue, body is raw */
805	    if (opts & 2) {
806	        /* OPT_NAKED */
807	        emit_comment("NAKED procedure -- no prologue/epilogue");
808	        cg_block(body);
809	        return;
810	    }
811	
812	    /* Standard prologue: push fp, push r2, push r1, mov fp,sp */
813	    emit_prologue();
814	
815	    /* Allocate stack space for locals (sub sp, frame_size) */
816	    frame_sz = layout_frame_size;
817	    if (frame_sz > 0) {
818	        if (frame_sz >= -128 && frame_sz <= 127) {
819	            emit_str(EMIT_INDENT);
820	            emit_str("lc      r0,");
821	            emit_int(frame_sz);
822	            emit_nl();
823	        } else {
824	            emit_str(EMIT_INDENT);
825	            emit_str("la      r0,");
826	            emit_int(frame_sz);
827	            emit_nl();
828	        }
829	        emit_instr("sub     sp,r0");
830	    }
831	
832	    /* Emit body statements */
833	    cg_block(body);
834	
835	    /* Standard epilogue: mov sp,fp, pop r1, pop r2, pop fp, jmp (r1) */
836	    emit_epilogue();
837	}
838	
839	/* Emit code for all procedures in a program AST.
840	 * Walks top-level children and codegen's each PROC node.
841	 * Handles layout_proc() and scope management for each. */
842	
843	void cg_program_procs(int prog_node) {
844	    int child;
845	
846	    if (prog_node == NODE_NULL) return;
847	
848	    child = nd_left[prog_node];
849	    while (child != NODE_NULL) {
850	        if (nd_kind[child] == NODE_PROC) {
851	            /* Layout procedure (enters scope, assigns offsets) */
852	            layout_proc(child);
853	            /* Emit code */
854	            cg_proc(child);
855	            /* Exit procedure scope */
856	            sym_exit_scope();
857	        }
858	        child = nd_next[child];
859	    }
860	}
861	
862	#endif /* CODEGEN_H */
863

