        errs = errs + 1;
    } else {
        cg_program_procs(prog);
        out = emit_output();
        uart_putstr(out);
        if (!str_find(out, "la      r2,_FOO")) {
            uart_puts("  FAIL: missing la r2,_FOO");
            errs = errs + 1;
        }
        if (!str_find(out, "jal     r1,(r2)")) {
            uart_puts("  FAIL: missing jal");
            errs = errs + 1;
