            uart_puts("  FAIL: missing arg2 store at 3(sp)");
            errs = errs + 1;
        }
        if (!str_find(out, "sw      r0,6(sp)")) {
            uart_puts("  FAIL: missing arg3 store at 6(sp)");
            errs = errs + 1;
        }
        if (!str_find(out, "la      r2,_ADD3")) {
            uart_puts("  FAIL: missing call target");
            errs = errs + 1;
        }
