    uart_putstr("  array desc idx=");
    print_int(desc);
    uart_putchar(10);
    td_print(desc);

    desc = td_make_array(TYPE_INT24, 10);
    uart_putstr("  array desc idx=");
    print_int(desc);
    uart_putchar(10);
    td_print(desc);

    /* Test 7: record type descriptor from AST */
    uart_puts("--- record descriptor ---");
    arena_init();
    ast_init();
    parse_init("DCL 1 POINT, 3 X INT(24), 3 Y INT(24);");
